import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.1N8rnUr9.js";const c=JSON.parse('{"title":"Global Settings","description":"","frontmatter":{},"headers":[],"relativePath":"features/global-settings.md","filePath":"features/global-settings.md","lastUpdated":1775715475000}'),n={name:"features/global-settings.md"};function i(r,e,l,d,g,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h1><p>The <strong>Settings</strong> page allows you to control the overall behavior of TubeBay. Changes made here apply to all videos and product pages across your store.</p><h2 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><ul><li><strong>Connection Method:</strong> Toggle between Google OAuth 2.0 and Manual API Key.</li><li><strong>Sync Frequency:</strong> Set how often TubeBay should check for new videos (e.g., 12 hours, 24 hours, or Weekly).</li><li><strong>Clear Cache:</strong> Manually clear the transients that store your video library and product mappings.</li></ul><h2 id="video-library-settings" tabindex="-1">Video Library Settings <a class="header-anchor" href="#video-library-settings" aria-label="Permalink to &quot;Video Library Settings&quot;">​</a></h2><ul><li><strong>Videos Per Page:</strong> Control how many videos are displayed at once in the Library tab.</li><li><strong>Thumbnail Quality:</strong> Choose between Low, Medium, and High resolution thumbnails fetched from YouTube.</li></ul><h2 id="advanced-settings" tabindex="-1">Advanced Settings <a class="header-anchor" href="#advanced-settings" aria-label="Permalink to &quot;Advanced Settings&quot;">​</a></h2><ul><li><strong>Uninstall Data:</strong> Choose whether to keep or delete all TubeBay data (mappings, settings) when the plugin is deleted.</li><li><strong>Debug Logging:</strong> Enable detailed logs for troubleshooting API connection issues. Logs can be viewed at <code>wp-content/uploads/tubebay-logs/</code>.</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>By default, only users with the <code>manage_options</code> capability (Administrators) can access the TubeBay settings and library. You can use a roles and capabilities editor plugin to grant access to Shop Managers if needed.</p>',10)])])}const b=t(n,[["render",i]]);export{c as __pageData,b as default};
